import{_ as a,o as l,c as e,a2 as r}from"./chunks/framework.ZhLefgN8.js";const c=JSON.parse('{"title":"期权链","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/options/options-chain.md","filePath":"zh-CN/derivatives/options/options-chain.md"}'),o={name:"derivatives/options/options-chain.md"};function d(i,t,h,n,s,p){return l(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="期权链" tabindex="-1">期权链 <a class="header-anchor" href="#期权链" aria-label="Permalink to &quot;期权链&quot;">​</a></h1><p>期权链页面集中展示某支股票所有可交易期权合约，方便快速筛选到期日、行权价，以及对比 Call 和 Put 的行情数据。</p><h2 id="进入期权链" tabindex="-1">进入期权链 <a class="header-anchor" href="#进入期权链" aria-label="Permalink to &quot;进入期权链&quot;">​</a></h2><p>在股票详情页顶部 Tab 栏切换至「期权链」，即可查看该标的的所有期权合约。</p><p>页面顶部显示标的股票名称、当前价格及涨跌幅（含交易时段标识）。</p><h2 id="页面布局" tabindex="-1">页面布局 <a class="header-anchor" href="#页面布局" aria-label="Permalink to &quot;页面布局&quot;">​</a></h2><p>期权链页面分为三个层次：</p><ol><li><strong>筛选栏</strong>：策略类型 + Call/Put 方向选择</li><li><strong>Call:Put 成交量统计</strong>：展示多空情绪比例</li><li><strong>到期日横向滚动列表</strong>：快速切换不同到期日</li><li><strong>合约列表</strong>：以行权价为中轴，左侧为 Call、右侧为 Put，当前股价所在行以蓝色高亮（价内期权也以蓝色标注）</li></ol><h2 id="策略类型" tabindex="-1">策略类型 <a class="header-anchor" href="#策略类型" aria-label="Permalink to &quot;策略类型&quot;">​</a></h2><p>点击筛选栏左侧的策略选择器可切换策略类型：</p><ul><li><strong>单腿期权</strong>：单个 Call 或 Put 合约</li></ul><p>组合策略（如价差、跨式等）在相应选项下展示。</p><h2 id="call-put-方向筛选" tabindex="-1">Call / Put 方向筛选 <a class="header-anchor" href="#call-put-方向筛选" aria-label="Permalink to &quot;Call / Put 方向筛选&quot;">​</a></h2><p>点击方向选择器可在以下选项间切换：</p><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td>全部</td><td>同时显示 Call 和 Put 两列</td></tr><tr><td>Call</td><td>仅显示看涨期权</td></tr><tr><td>Put</td><td>仅显示看跌期权</td></tr></tbody></table><p>选择「全部」时，行权价居中显示，Call 在左、Put 在右；选择单一方向时，数据列更宽，便于查看更多字段。</p><h2 id="call-put-成交量比" tabindex="-1">Call:Put 成交量比 <a class="header-anchor" href="#call-put-成交量比" aria-label="Permalink to &quot;Call:Put 成交量比&quot;">​</a></h2><p>筛选栏中间显示当日 Call 和 Put 的成交量及比例，例如「62:38」表示当日 Call 成交量占 62%、Put 占 38%，可快速感知市场多空倾向。</p><h2 id="到期日选择" tabindex="-1">到期日选择 <a class="header-anchor" href="#到期日选择" aria-label="Permalink to &quot;到期日选择&quot;">​</a></h2><p>横向滑动到期日列表选择目标到期日，每个到期日标签显示：</p><ul><li>日期（如 04/17）</li><li>距今天数（如 15 天）</li><li>角标「W」表示周期权（Weekly），无角标为月期权</li></ul><p>当前选中的到期日会高亮显示。</p><h2 id="合约列表数据列" tabindex="-1">合约列表数据列 <a class="header-anchor" href="#合约列表数据列" aria-label="Permalink to &quot;合约列表数据列&quot;">​</a></h2><p>合约列表左右两侧各展示若干行情字段，可通过右上角<strong>布局设置</strong>按钮自定义。常见字段包括：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>最新价</td><td>期权合约当前成交价</td></tr><tr><td>涨跌幅</td><td>相较昨收的涨跌百分比</td></tr><tr><td>成交量</td><td>当日成交合约张数</td></tr><tr><td>未平仓数</td><td>当前持仓合约总数</td></tr><tr><td>隐含波动率（IV）</td><td>由期权价格反推的市场预期波动率</td></tr><tr><td>Delta</td><td>标的价格变动 1 单位时期权价格的变化量</td></tr></tbody></table><p>价内（ITM）合约行以蓝色背景标识；当前标的价格所在行以分隔线标注，便于区分实值与虚值期权。</p><h2 id="盘前交易" tabindex="-1">盘前交易 <a class="header-anchor" href="#盘前交易" aria-label="Permalink to &quot;盘前交易&quot;">​</a></h2><p>勾选「支持盘前交易」复选框后，列表将包含可在盘前时段交易的期权合约。</p><h2 id="布局设置" tabindex="-1">布局设置 <a class="header-anchor" href="#布局设置" aria-label="Permalink to &quot;布局设置&quot;">​</a></h2><p>点击右上角设置图标，可调整合约列表显示的数据列：选择要展示的字段并拖动排序，设置实时生效。</p><h2 id="进入合约详情" tabindex="-1">进入合约详情 <a class="header-anchor" href="#进入合约详情" aria-label="Permalink to &quot;进入合约详情&quot;">​</a></h2><p>点击任意期权合约行，进入该期权的详情页，可查看完整行情数据（Delta、Gamma、Theta、Vega、Rho、隐含波动率、历史波动率等）、K<br> 线图表、期权计算器，以及发起买入/卖出下单。</p>',32)])])}const b=a(o,[["render",d]]);export{c as __pageData,b as default};
